mapper.select:
SELECT

FROM ai_formula_function
WHERE tenant_id = #{tenantId}

  AND (
    function_code LIKE CONCAT('%', #{keyword}, '%')
    OR display_name LIKE CONCAT('%', #{keyword}, '%')
    OR description LIKE CONCAT('%', #{keyword}, '%')
  )


  AND category = #{category}


  AND source_type = #{sourceType}


  AND status = #{status}

ORDER BY sort_order ASC, id ASC

SELECT

FROM ai_formula_function
WHERE tenant_id = #{tenantId}
  AND function_code = #{functionCode}
LIMIT 1

SELECT

FROM ai_formula_function_version
WHERE tenant_id = #{tenantId}
  AND function_code = #{functionCode}
ORDER BY create_time DESC, id DESC

SELECT

FROM ai_formula_function_install
WHERE tenant_id = #{tenantId}
  AND function_code = #{functionCode}
LIMIT 1

SELECT

FROM ai_formula_function f
LEFT JOIN ai_formula_function_install i
  ON i.tenant_id = f.tenant_id
 AND i.function_code = f.function_code
LEFT JOIN ai_formula_function_version v
  ON v.tenant_id = f.tenant_id
 AND v.function_code = f.function_code
 AND v.version = COALESCE(i.installed_version, f.current_version, f.latest_version, '1.0.0')
WHERE f.tenant_id = #{tenantId}

  AND (
    f.function_code LIKE CONCAT('%', #{query.keyword}, '%')
    OR f.display_name LIKE CONCAT('%', #{query.keyword}, '%')
    OR f.description LIKE CONCAT('%', #{query.keyword}, '%')
  )


  AND f.category = #{query.category}


  AND f.source_type = #{query.sourceType}


  AND f.status = #{query.status}


  AND i.install_status = #{query.installStatus}


  AND i.enabled = #{query.enabled}

ORDER BY f.sort_order ASC, f.id ASC
